INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('aboriginal-a5729396-moex-00064', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-114-34c7f7f6', 'sub-aboriginal-a5729396-02', NULL, 'single_choice', '「除了我們今天常見的炒麵、炒飯、豆腐乾和肉類製品外，有些食材是在宋朝看不到的，雖然海外貿 易發達，但航線只限亞洲、歐洲和非洲，美洲新大陸還沒被發現，因此宋朝人吃不到花生、馬鈴薯、 玉米、辣椒、番茄、鳳梨和蘋果，因為這些外來作物要直到明朝才進口。但宋朝的四川、湖南人嗜辣， 那時生意興隆的川菜館怎麼經營？原來宋朝人將胡椒代替辣椒入菜，胡椒是外來種，在西漢時便已傳 入。」 根據上文，倘若穿越時空到宋朝吃一頓餐，可以吃到的餐點是：', '["番茄炒蛋麵", "椒鹽豆腐乾", "鳳梨蛋炒飯", "馬鈴薯燉肉"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:45+00:00", "source_pdf_sha1": "ec3d1305ccbd", "answer_pdf_sha1": "e298021d32ef", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00065', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-114-34c7f7f6', 'sub-aboriginal-a5729396-02', NULL, 'single_choice', '「建築是『衣食住』中的第三項，是一個民族在地理、地質、氣候、政治、社會、宗教等影響下的產 品。人類在物質或思想上的變遷，建築便極忠實地反映出來，所以歐洲的史家稱建築為『歷史之鏡』。 中國的建築是世界上歷史最長，生命最久，散布區域最廣的。歐洲的建築，在各區域裡隨著民族文化 而興盛衰亡，中國建築卻永久賡續。雖然在思想上中華民族受過外來宗教的影響，在政治上受過異族 的統治，但卻仍保持其數千年的特徵。」 根據上文，下列選項何者最符合文意？', '["中國因為未曾受過異族的統治，所以建築能夠保持數千年的特徵", "歐洲建築因為不受民族文化興亡影響，而具有永久賡續的特殊性", "建築之所以被稱為「歷史之鏡」，是因為它反映出複雜的歷史背景", "「建築是『衣食住』中的第三項」，透露「住」處於最重要的地位"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:45+00:00", "source_pdf_sha1": "ec3d1305ccbd", "answer_pdf_sha1": "e298021d32ef", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00066', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-114-34c7f7f6', 'sub-aboriginal-a5729396-02', NULL, 'single_choice', '「陳有蘭溪的谷頭與其上方鞍部的落差高達580公尺，但鞍部的另一側降至荖濃溪谷頭的落差卻僅有 180公尺。由於重力加速度的作用，陳有蘭溪向源侵蝕的能力，當然遠較荖濃溪為強。分水嶺因而逐 漸南移，草原日趨縮小，鞍部的高度則繼續降低。長此以往，強勢的陳有蘭溪的上游源頭，甚至於終 會切入荖濃溪的河谷，將之截斷，發生所謂河川襲奪的現象，搶去原屬荖濃溪的水源。」 關於陳有蘭溪和荖濃溪的敘述，下列選項最適當的是：', '["陳有蘭溪的河床深度比荖濃溪還深", "荖濃溪的水流速度比陳有蘭溪湍急", "草原縮小原因是荖濃溪的水量不足以沾溉", "河川侵奪現象將使陳有蘭溪水源更加豐沛"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:45+00:00", "source_pdf_sha1": "ec3d1305ccbd", "answer_pdf_sha1": "e298021d32ef", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00067', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-114-34c7f7f6', 'sub-aboriginal-a5729396-02', NULL, 'single_choice', '「華格納說：『想像力使人發明老虎鉗以延伸其大拇指，發明錘子以加強其拳與臂的力量。一步一步 的想像力被誘發、啟導，並且常常促使人類的力量達到前所未有的地步，此種力量現在人類已經能很 快地領悟並予以把握。』」 根據上文，最符合文意的是：', '["失去想像力的人類會逐漸衰弱滅亡", "想像力可以改變現況並且打破侷限", "拳與臂的力量取決於想像力的強弱", "想像力所仰賴的是自由而不是學習"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:45+00:00", "source_pdf_sha1": "ec3d1305ccbd", "answer_pdf_sha1": "e298021d32ef", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00068', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-114-34c7f7f6', 'sub-aboriginal-a5729396-02', NULL, 'single_choice', '「我不能想像一致的步調追逐著同樣的風尚，會是多麼可厭的社會現象，時裝髮型尚且如此，何況詩 的文學！我們的表達方式和著眼點在變化，但詩的精神意圖和文化目標，詩對藝術的超越性之執著， 以及它對現實是非的關懷，寓批判和規勸於文字指涉與聲韻跌宕之中，這一切，是不太可能隨政治局 面或意識型態去改變的。」 關於本文的解釋，敘述錯誤的選項是：', '["詩可以表達對現實社會的關懷", "在創作上應避免「人云亦云」", "變化與超越是詩創作追求的唯一目標", "政治和意識形態不會改變藝術創作的本質"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:45+00:00", "source_pdf_sha1": "ec3d1305ccbd", "answer_pdf_sha1": "e298021d32ef", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00069', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-114-34c7f7f6', 'sub-aboriginal-a5729396-02', NULL, 'single_choice', '「除了社會共同的信念以外，每個人都有他的成見，有他自以為是的想法。學哲學的人，首先要接受 的訓練，便是從不同的層次、不同的角度看問題，把生活經驗的每一部分都放在整體的立場去考察。」 根據上文，下列選項何者最符合文意？', '["哲學最能滿足人在知性層面的思考", "偉大的哲學系統本身就是包羅萬象", "哲學有益於消除個人偏見和獨斷態度", "哲學訓練讓人可以比較貼近生活經驗"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:45+00:00", "source_pdf_sha1": "ec3d1305ccbd", "answer_pdf_sha1": "e298021d32ef", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00070', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-114-34c7f7f6', 'sub-aboriginal-a5729396-02', NULL, 'single_choice', '「海獵人常常一個人下潛，就必須靜止水底十幾二十秒；直到魚群忽視人的存在，放鬆游過來被瞄準 捕獲。體悟靜心從容之道，是每個海獵人最深的功課，除了上上下下不斷補氣潛行的過程，其餘時間 都是海裡的潛伏者。海獵人著迷彩色的防寒衣，就是為了把自己偽裝成海裡的山水。」 根據上文，下列選項敘述正確的是：', '["海獵人是海裡的潛伏者，需靜止水底待魚群放鬆警戒再行動", "為了增加捕獲率，海獵人通常上下二人一組，一潛伏一瞄準", "技巧高超的海獵人除了補氣次數較少，也擅長主動追蹤魚群", "單色防寒衣在海裡混淆視覺的效果佳，有迷彩色則過於顯眼"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:45+00:00", "source_pdf_sha1": "ec3d1305ccbd", "answer_pdf_sha1": "e298021d32ef", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00071', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-114-34c7f7f6', 'sub-aboriginal-a5729396-02', NULL, 'single_choice', '「在臺有戶籍國民在國內申請換發普通護照，可由本人親自到場或委任代理人代為申請換照。委任代 辦申請案，申請人須先填妥委任書及相關文件，代理人可為親屬、或與申請人現屬同一機關、學校、 公司、經政府立案團體的人員，或委任交通部觀光署核准的綜合或甲種旅行社。如非上述委任代辦關 係者，代理人須出具經公證的申請人委任書，始得代為申請。」 根據上文，下列那個選項的代理人，須出具經公證的申請人委任書，始得代為申請？', '["申請人的親屬", "申請人的好友", "申請人公司的同仁", "申請人委任的合法旅行社"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:45+00:00", "source_pdf_sha1": "ec3d1305ccbd", "answer_pdf_sha1": "e298021d32ef", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00072', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-114-34c7f7f6', 'sub-aboriginal-a5729396-02', NULL, 'single_choice', '「德國哲學家叔本華曾說：『一個人只有在感覺到孤獨的時候，才能成為真正的自己。不愛孤獨的人， 無非就是一個不愛自由的人。』」 根據上文，下列選項最符合文意的是：', '["愛孤獨的人，往往害怕自由", "受不了孤獨，必不懂愛自己", "愛自由的人，一定不會孤獨", "要成為自己，要先面對孤獨"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:45+00:00", "source_pdf_sha1": "ec3d1305ccbd", "answer_pdf_sha1": "e298021d32ef", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00073', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-114-34c7f7f6', 'sub-aboriginal-a5729396-02', NULL, 'single_choice', '「最荒謬的真理，就是認為實際的人生中，有一個絕對不變的真理。假如，你不再去感受隨時變化的 實際人生，而自認為已經找到一個絕對不變的真理，就將它封藏在心靈中，永不捨棄；那麼，你便已 停止成長。」 根據上文，下列選項何者最符合文意？', '["「真理」是成長的關鍵", "「真理」應能與時俱化", "「真理」必須封藏在心靈中", "「真理」是一種個人的感受"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:45+00:00", "source_pdf_sha1": "ec3d1305ccbd", "answer_pdf_sha1": "e298021d32ef", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL)
